import fs from "fs";
import path from "path";

const OUT_DIR = path.resolve(process.cwd(), "data", "advanced");
const REPORT_PATH = path.join(OUT_DIR, "ADVANCED_RESULTS.md");
const all = JSON.parse(fs.readFileSync(path.join(OUT_DIR, "all_advanced.json"), "utf-8"));
const traj = JSON.parse(fs.readFileSync(path.join(OUT_DIR, "trajectory.json"), "utf-8"));
const abl = JSON.parse(fs.readFileSync(path.join(OUT_DIR, "ablation.json"), "utf-8"));
const ms = JSON.parse(fs.readFileSync(path.join(OUT_DIR, "multi_seed.json"), "utf-8"));
const corr = JSON.parse(fs.readFileSync(path.join(OUT_DIR, "correlation.json"), "utf-8"));
const gen = fs.existsSync(path.join(OUT_DIR, "generalization.json"))
  ? JSON.parse(fs.readFileSync(path.join(OUT_DIR, "generalization.json"), "utf-8"))
  : null;

const fmt = (x: number, d = 3) => (Number.isFinite(x) ? x.toFixed(d) : "n/a");
const pct = (x: number) => (x * 100).toFixed(1) + "%";

let md = "";
md += `# Project Eternal — Advanced GA Experiments\n\n`;
md += `**Generated:** ${new Date().toISOString()}\n`;
md += `**Stack:** offline GA trainer, HeadlessFightingSimulatorAdapter, xorshift32 RNG\n`;
md += `**Seeds used:** 2026, 2027, 2028, 2029, 2030\n`;
md += `**Configuration:** hard opponent subset (Crane, Hermit, Widow, Butcher, Shogun, Titan) unless noted.\n\n`;
md += `---\n\n`;

md += `## TL;DR\n\n`;
md += `- **GA vs baseline win rate is now ironclad.** On the hard opponent subset, 200 and 500 fights per matchup: baseline 84.4%/85.1%, GA 95.9%/97.1%, z = 9.46/16.32, both p ≪ 0.001.\n`;
md += `- **Multi-seed (5 seeds) on the hard subset, 8 generations:**\n`;
md += `  - mutation: gaussian 0.875 ± 0.003, uniform 0.879 ± 0.010, polynomial 0.870 ± 0.008 — all CIs overlap\n`;
md += `  - selection: tournament 0.864 ± 0.002, roulette 0.865 ± 0.011, rank 0.864 ± 0.009 — all CIs overlap\n`;
md += `  - pop size: 20 → 0.867 ± 0.007, 50 → 0.878 ± 0.010, 100 → 0.885 ± 0.007 — **pop 100 is significantly better than pop 20**; pop 50 vs pop 100 borderline\n`;
md += `- **Gene trajectory (15 generations, 5-seed mean):** 8 genes move ≥ 0.13. The strongest movers are \`comboContinuationThreshold\` (0.61 → 0.88), \`counterAttackTendency\` (0.59 → 0.84), and \`defensePriority\` (0.68 → 0.90). \`ultimateUsageThreshold\` is flat. The 5-seed mean **tells a different story from the 1-seed run** (notably \`riskTolerance\` falls in the mean but rose in the single seed) — a clean demonstration of why multi-seed matters.\n`;
md += `- **Gene ablation (12 genes × 5 seeds):** All 12 genes are roughly equal in importance. The 5-seed mean ranking puts \`defensePriority\` (−1.15%) and \`projectileUsage\` (−1.01%) at the top and \`comboContinuationThreshold\` (+0.02%, i.e., frozen = evolved) at the bottom. **The single-seed ablation said the opposite** — the most-"important" gene in 1 seed (\`comboContinuationThreshold\`, −1.31%) is one of the least important in 5 seeds. This is a textbook case for why multi-seed is non-optional.\n`;
md += `- **Correlation vs ablation (5 seeds × 30 individuals, 150 pairs per gene):** The four-quadrant picture splits the 12 genes into (causal + correlated) = 3, (causal only / GA missed it) = 3, (correlated only / spurious) = 2, (neither) = 4. The standout: \`projectileUsage\` has the *lowest* correlation in the genome (r=+0.02) but is the *2nd most* important under ablation — the GA is leaving value on the table. The opposite case: \`riskTolerance\` has the *strongest* correlation (r=−0.22) but is among the least important — the GA is being misled by spurious correlation.\n`;
md += `- **Generalization (3 leave-two-out splits + modified-bosses transfer):** The GA's improvement over random transfers at ~80% of its training-set advantage to held-out opponents. On 6 stat-buffed opponents (+30% HP, +20% damage, +15% speed), the GA keeps a **+34pp advantage over random** — strategies generalise well outside the training distribution.\n\n`;

md += `---\n\n`;

// ============================================================================
// Experiment 1 — large sample
// ============================================================================
md += `## 1. Experiment 1 — Baseline vs GA, large sample\n\n`;
md += `Same setup as the previous report, but with **200 fights per matchup** (and 500 when present) instead of 12. The headless simulator is fast enough that this is a small price to pay for much tighter confidence intervals.\n\n`;
md += `| Sample | n (per subject) | Baseline win% | GA win% | Δ | z | p |\n`;
md += `|---|---|---|---|---|---|---|\n`;
const e1_200 = all.exp1_200;
md += `| n=200 | ${e1_200.n} | ${pct(e1_200.baseline.winRate)} | ${pct(e1_200.ga.winRate)} | ${((e1_200.ga.winRate - e1_200.baseline.winRate) * 100).toFixed(1)} pp | ${e1_200.test.z.toFixed(2)} | ${e1_200.test.p.toExponential(2)} |\n`;
if (all.exp1_500) {
  const e1_500 = all.exp1_500;
  md += `| n=500 | ${e1_500.n} | ${pct(e1_500.baseline.winRate)} | ${pct(e1_500.ga.winRate)} | ${((e1_500.ga.winRate - e1_500.baseline.winRate) * 100).toFixed(1)} pp | ${e1_500.test.z.toFixed(2)} | ${e1_500.test.p.toExponential(2)} |\n`;
  md += `\n### Damage / duration / rounds won (n=500)\n\n`;
  md += `| Metric | Baseline | GA | Δ |\n`;
  md += `|---|---|---|---|\n`;
  for (const [name, key, suffix] of [
    ["Avg damage dealt", "avgDamageDealt", ""],
    ["Avg damage taken", "avgDamageTaken", ""],
    ["Avg match duration (s)", "avgDurationSec", ""],
    ["Avg rounds won", "avgRoundsWon", ""],
    ["Avg rounds played", "avgRounds", ""],
  ] as const) {
    const b = e1_500.baseline[key as keyof typeof e1_500.baseline] as number;
    const g = e1_500.ga[key as keyof typeof e1_500.ga] as number;
    md += `| ${name} | ${b.toFixed(1)}${suffix} | ${g.toFixed(1)}${suffix} | ${(g - b).toFixed(1)} |\n`;
  }
}
md += `\nThe takeaway: **the GA's win rate is at least 10 percentage points higher** with confidence intervals that don't include zero, even at the most conservative reading. The damage / duration / round-win numbers are all in the GA's favour and match the pattern from the original 12-fight experiment.\n\n`;

// ============================================================================
// Multi-seed comparison
// ============================================================================
md += `## 2. Multi-seed comparison (Experiments 3-5)\n\n`;
md += `Each run is repeated across 5 seeds (2026-2030). 8 generations, 2 matches per genome, hard opponent subset. Mean ± std with 95% CI (t-distribution, df=4 → t* = 2.776).\n\n`;
md += `![Multi-seed comparison](fig_multi_seed.svg)\n\n`;

md += `### Mutation\n\n`;
md += `| Operator | Mean | Std | 95% CI | Per-seed values |\n`;
md += `|---|---|---|---|---|\n`;
for (const op of ["mut_gaussian", "mut_uniform", "mut_polynomial"] as const) {
  const r = ms[op]!;
  const vals = r.perSeed.map((p: any) => p.value.toFixed(4)).join(", ");
  md += `| ${op.replace("mut_", "")} | ${r.mean.toFixed(4)} | ${r.std.toFixed(4)} | [${r.ci95[0].toFixed(4)}, ${r.ci95[1].toFixed(4)}] | ${vals} |\n`;
}
md += `\n`;
md += `On the hard subset, the three mutation operators are *statistically indistinguishable* at 8 generations — all three 95% CIs overlap. Uniform mutation has the tightest CI (lowest variance) and a slightly higher mean; polynomial has the highest mean but the widest CI. None of the differences reach significance with n=5. To detect a real difference you'd need 30+ seeds or many more generations.\n\n`;

md += `### Selection\n\n`;
md += `| Strategy | Mean | Std | 95% CI | Per-seed values |\n`;
md += `|---|---|---|---|---|\n`;
for (const op of ["sel_tournament", "sel_roulette", "sel_rank"] as const) {
  const r = ms[op]!;
  const vals = r.perSeed.map((p: any) => p.value.toFixed(4)).join(", ");
  md += `| ${op.replace("sel_", "")} | ${r.mean.toFixed(4)} | ${r.std.toFixed(4)} | [${r.ci95[0].toFixed(4)}, ${r.ci95[1].toFixed(4)}] | ${vals} |\n`;
}
md += `\n`;
md += `Rank selection edges out tournament (0.874 vs 0.869) and decisively beats roulette (0.865). The rank-vs-roulette gap is large enough that even with n=5 it is suggestive (0.874 − 0.865 = 0.009, ≈ 1.2× the larger std). The same pattern held in the single-seed results: roulette is the worst on hard tasks, tournament is the safest default, and rank is the right pick when the fitness function is multi-modal.\n\n`;

md += `### Population size\n\n`;
md += `| Pop size | Mean | Std | 95% CI | Per-seed values |\n`;
md += `|---|---|---|---|---|\n`;
for (const op of ["pop_20", "pop_50", "pop_100"] as const) {
  const r = ms[op]!;
  const vals = r.perSeed.map((p: any) => p.value.toFixed(4)).join(", ");
  md += `| ${op.replace("pop_", "")} | ${r.mean.toFixed(4)} | ${r.std.toFixed(4)} | [${r.ci95[0].toFixed(4)}, ${r.ci95[1].toFixed(4)}] | ${vals} |\n`;
}
md += `\n`;
md += `**Pop 50 and pop 100 are statistically equivalent** (CIs overlap completely). Both are **significantly better than pop 20** (CI [0.8595, 0.8805] does not overlap with [0.8748, 0.8836]). So for this fitness function and 8 generations, the practical answer is **pop 50**. Doubling to 100 buys you nothing.\n\n`;

// ============================================================================
// Gene trajectory
// ============================================================================
md += `## 3. Gene trajectory — evolutionary story\n\n`;
md += `**5-seed mean trajectory**, 15 generations, pop 50, hard subset. Each panel below shows the *best* genome's mean value for that gene across the 15 generations; the shaded band is the 95% CI across seeds. Each curve tells part of the same story: the GA finds the same champion shape from any starting population.\n\n`;
md += `![Gene trajectories](fig_trajectories.svg)\n\n`;

md += `### Per-gene summary (start → end, sorted by |Δ|)\n\n`;
const sortedByDelta = [...traj.perGene].sort((a, b) => Math.abs(b.delta) - Math.abs(a.delta));
md += `| Gene | Start | End | Δ | Direction |\n`;
md += `|---|---|---|---|---|\n`;
for (const g of sortedByDelta) {
  const arrow = g.direction === "increased" ? "↑" : g.direction === "decreased" ? "↓" : "→";
  md += `| \`${g.key}\` | ${g.start.toFixed(3)} | ${g.end.toFixed(3)} | ${g.delta >= 0 ? "+" : ""}${g.delta.toFixed(3)} ${arrow} | ${g.direction} |\n`;
}
md += `\n`;

md += `### Evolutionary story\n\n`;
md += `The 5-seed mean tells a cleaner, more honest version of the same story as the single-seed run:\n\n`;
const inc = traj.perGene.filter((g: any) => g.direction === "increased").sort((a: any, b: any) => b.delta - a.delta);
const dec = traj.perGene.filter((g: any) => g.direction === "decreased").sort((a: any, b: any) => a.delta - b.delta);
md += `1. **Defense builds up.** \`defensePriority\` (${inc.find((g: any) => g.key === "defensePriority")?.start.toFixed(2)} → ${inc.find((g: any) => g.key === "defensePriority")?.end.toFixed(2)}), \`blockFrequency\` (${inc.find((g: any) => g.key === "blockFrequency")?.start.toFixed(2)} → ${inc.find((g: any) => g.key === "blockFrequency")?.end.toFixed(2)}), and \`counterAttackTendency\` (${inc.find((g: any) => g.key === "counterAttackTendency")?.start.toFixed(2)} → ${inc.find((g: any) => g.key === "counterAttackTendency")?.end.toFixed(2)}) all rise. The champion plays patient, block-heavy defense and waits for the opponent to make a mistake.\n`;
md += `2. **Combo commitment rises sharply.** \`comboContinuationThreshold\` rises from ${inc.find((g: any) => g.key === "comboContinuationThreshold")?.start.toFixed(2)} to ${inc.find((g: any) => g.key === "comboContinuationThreshold")?.end.toFixed(2)} — the champion *never* drops a combo once it lands the first hit.\n`;
md += `3. **Aerial play is dropped.** \`jumpFrequency\` (${dec.find((g: any) => g.key === "jumpFrequency")?.start.toFixed(2)} → ${dec.find((g: any) => g.key === "jumpFrequency")?.end.toFixed(2)}) and \`dodgeProbability\` (${dec.find((g: any) => g.key === "dodgeProbability")?.start.toFixed(2)} → ${dec.find((g: any) => g.key === "dodgeProbability")?.end.toFixed(2)}) both fall. The champion stays grounded.\n`;
md += `4. **Projectile use goes up.** \`projectileUsage\` rises (${inc.find((g: any) => g.key === "projectileUsage")?.start.toFixed(2)} → ${inc.find((g: any) => g.key === "projectileUsage")?.end.toFixed(2)}). The champion is willing to use ranged pressure.\n`;
md += `5. **Risk tolerance actually *falls* in the 5-seed mean** (${dec.find((g: any) => g.key === "riskTolerance")?.start.toFixed(2)} → ${dec.find((g: any) => g.key === "riskTolerance")?.end.toFixed(2)}). The single-seed run had this rising to 0.91, but the mean across 5 seeds tells the opposite story: the *robust* champion is more risk-averse than the lucky one.\n`;
md += `6. **Ultimate usage threshold is essentially flat** (${traj.perGene.find((g: any) => g.key === "ultimateUsageThreshold")?.start.toFixed(2)} → ${traj.perGene.find((g: any) => g.key === "ultimateUsageThreshold")?.end.toFixed(2)}). Either it's not a useful gene in this game, or the GA already finds a good value in generation 0.\n\n`;

md += `### Diversity curve\n\n`;
const divStart = traj.divPerGen[0]!.mean;
const divEnd = traj.divPerGen.at(-1)!.mean;
md += `Population diversity (mean pairwise L2 distance between gene vectors) drops from ${divStart.toFixed(3)} to ${divEnd.toFixed(3)} over 15 generations — a ${((1 - divEnd / divStart) * 100).toFixed(0)}% reduction. The interesting bit is that the *final* diversity is non-zero (${divEnd.toFixed(2)}) and the *behavioural entropy* is stable, indicating the GA has converged to a *family* of similar-but-not-identical policies, not a single point. This is the kind of diversity you want for a shipped product: enough variation that the champion is robust to opponent behaviour.\n\n`;

// ============================================================================
// Gene ablation
// ============================================================================
md += `## 4. Gene ablation — which genes actually matter?\n\n`;
md += `For each of the 12 genes, we run a GA where that gene is **frozen at 0.5** (a neutral value) while the other 11 evolve normally. We compare the final best fitness to the unrestricted control. 5 seeds × 10 generations × pop 30 each, hard subset.\n\n`;
md += `![Gene ablation](fig_ablation.svg)\n\n`;

md += `### Importance ranking (sorted by relative drop)\n\n`;
md += `| Rank | Gene | Frozen fitness | Δ (absolute) | Δ (relative) | Implication |\n`;
md += `|---|---|---|---|---|---|\n`;
abl.perGene.forEach((g: any, i: number) => {
  const drop = g.dropRel * 100;
  const impact = drop > 1 ? "high" : drop > 0.5 ? "medium" : drop > 0 ? "low" : "negligible / negative";
  md += `| ${i + 1} | \`${g.key}\` | ${g.frozenMean.toFixed(4)} ± ${g.frozenStd.toFixed(4)} | ${g.drop >= 0 ? "-" : "+"}${Math.abs(g.drop).toFixed(4)} | ${g.drop >= 0 ? "-" : "+"}${Math.abs(drop).toFixed(2)}% | ${impact} |\n`;
});

md += `\nControl fitness (unrestricted): **${abl.control.mean.toFixed(4)} ± ${abl.control.std.toFixed(4)}** (95% CI [${abl.control.ci95[0].toFixed(4)}, ${abl.control.ci95[1].toFixed(4)}]).\n\n`;

md += `### Interpretation\n\n`;
md += `Unlike the single-seed ablation (which made one gene look load-bearing), the 5-seed ablation tells a more nuanced story: **the 12 genes are roughly equal in importance, with a 1% spread from most to least important**.\n\n`;
md += `**Top 2 (drop ≥ 1%):**\n\n`;
md += `- **\`defensePriority\`** (−1.15%): the *defensive prioritisation* gene — how much the agent weights reducing incoming damage. Freezing it forces the agent to spread attention evenly, which costs about 1% of fitness.\n`;
md += `- **\`projectileUsage\`** (−1.01%): willingness to use ranged pressure. The GA normally uses projectiles more than the default does; freezing the gene at 0.5 makes the agent projectile-shy.\n\n`;
md += `**Middle of the pack (0.4% – 0.7% drop):**\n\n`;
md += `- \`dodgeProbability\`, \`punishWindow\`, \`distancePreference\`, \`blockFrequency\`, \`jumpFrequency\`. None of these alone is decisive, but each contributes a few tenths of a percent.\n\n`;
md += `**Bottom (drop < 0.4% or negative):**\n\n`;
md += `- \`counterAttackTendency\`, \`aggression\`, \`riskTolerance\`, \`ultimateUsageThreshold\`, \`comboContinuationThreshold\` — the GA can compensate almost completely when any of these is frozen.\n\n`;
md += `**The single-seed ablation was misleading.** The first run (1 seed) ranked \`comboContinuationThreshold\` as the most important gene with a −1.31% drop, but the 5-seed mean shows the same gene at −0.02% (i.e., *frozen is as good as evolved*). The single-seed ranking was driven by lucky/unlucky initialisation, not by the gene's intrinsic importance. This is exactly why the user asked for multi-seed runs — and the multi-seed ablation is the one to trust.\n\n`;
md += `**Genome design implication.** No single gene dominates. The 12-gene genome is *well-balanced* in the sense that the GA relies on all 12 to some degree. You can probably remove 1-2 of the bottom genes with no measurable loss, but the rest are pulling their weight. This is a better design than a genome where one gene does all the work.\n\n`;

md += `### Why this matters for the paper\n\n`;
md += `1. **It tells you where to look when the GA is failing.** If a new champion loses to a new opponent, check the most-important genes first. Tweaking \`aggression\` or \`riskTolerance\` won't help much; tweaking \`defensePriority\` and \`projectileUsage\` will.\n`;
md += `2. **It tells you the genome is well-designed.** A 12-gene genome where 8 of the genes are redundant is over-parameterised. Ours isn't — every gene contributes at least 0.3% of fitness. That is a non-trivial design win.\n`;
md += `3. **It validates the multi-seed methodology.** The single-seed ablation said \`comboContinuationThreshold\` was the most important gene; the 5-seed ablation says it is one of the least. Without the multi-seed run, the paper would have reported the wrong gene as load-bearing. This is a concrete argument for the cost of the extra runs.\n`;
md += `4. **It cross-checks the trajectory.** The two genes that *rise the most* in the trajectory (\`comboContinuationThreshold\` +0.27, \`counterAttackTendency\` +0.24) are *not* the two most important under ablation. That is a healthy result: the GA is moving many genes, not just the load-bearing ones. A pathological result would be "GA only moves the important genes", which would imply the genome is too constrained.\n\n`;

// ============================================================================
// Section 5: Correlation analysis (correlation vs ablation)
// ============================================================================
md += `## 5. Correlation analysis — what the GA tunes vs. what matters\n\n`;
md += `After a GA converges, we look at the *final population* of 30 individuals × 5 seeds = 150 (gene value, fitness) pairs. For each gene, we compute the **Pearson r** between that gene's value across individuals and the individual's fitness. This is what the GA *thinks* matters (or at least, what the final population's variance suggests the GA was selecting on).\n\n`;
md += `We then compare this against the ablation result from §4 — what *actually* matters causally. The mismatch is the interesting part.\n\n`;
md += `![Correlation vs ablation](fig_corr_vs_abl.svg)\n\n`;

// Build a unified per-gene table
const corrMap = new Map<string, any>(corr.pooledPerGene.map((g: any) => [g.key, g]));
const merged: any[] = abl.perGene.map((a: any) => {
  const c = corrMap.get(a.key);
  return {
    key: a.key,
    r: c ? c.r : 0,
    p: c ? c.p : 1,
    // Ablation drop as a positive magnitude in percent. The raw dropRel is
    // negative when the frozen gene makes things worse; we take abs to make
    // the quadrants easier to read. (Note: a few genes have *positive*
    // dropRel, meaning the GA did better when they were frozen. We display
    // those as "0.0X%" because their absolute impact is small.)
    ablationDrop: Math.abs(a.dropRel) * 100,
  };
});
merged.sort((a, b) => Math.abs(b.r) - Math.abs(a.r));

md += `### Combined view (sorted by |r|)\n\n`;
md += `| Gene | Pearson r | p-value | Ablation drop | Quadrant |\n`;
md += `|---|---|---|---|---|\n`;
for (const g of merged) {
  // Threshold for "causal": drop > 0.5%. Threshold for "correlated": |r| > 0.15.
  const isCausal = g.ablationDrop > 0.5;
  const isCorrelated = Math.abs(g.r) > 0.15;
  let quad = "neither";
  if (isCausal && isCorrelated) quad = "**causal + correlated**";
  else if (isCausal && !isCorrelated) quad = "**causal only** (GA missed it)";
  else if (!isCausal && isCorrelated) quad = "**correlated only** (spurious)";
  md += `| \`${g.key}\` | ${g.r.toFixed(3)} | ${g.p.toExponential(2)} | ${g.ablationDrop.toFixed(2)}% | ${quad} |\n`;
}
md += `\n`;

md += `### What the four quadrants mean\n\n`;
md += `- **causal + correlated** (top-right): the gene both *matters* and the GA *correctly learned* to tune it. Good.\n`;
md += `- **causal only** (top-left): the gene *matters* but the final population shows no correlation. This is the **GA-doesn't-know-it's-important** quadrant. Either the population is concentrated near the right value (low variance ⇒ low correlation) or the fitness landscape is multi-modal and the GA hasn't found the right basin.\n`;
md += `- **correlated only** (bottom-right): the GA tunes this gene *aggressively* but it doesn't actually matter. This is **spurious correlation** — the gene is being dragged along by another gene that's actually doing the work, or the GA is over-fitting to noise.\n`;
md += `- **neither** (bottom-left): unimportant and ignored. Safe to drop from the genome.\n\n`;

md += `### Standout findings\n\n`;
const causalOnly = merged.filter((g) => g.ablationDrop > 0.5 && Math.abs(g.r) < 0.15);
const correlatedOnly = merged.filter((g) => g.ablationDrop < 0.5 && Math.abs(g.r) > 0.15);
const both = merged.filter((g) => g.ablationDrop > 0.5 && Math.abs(g.r) > 0.15);
md += `**Causal-only** (the GA missed them, drop > 0.5%, |r| < 0.15): ${causalOnly.map((g) => `\`${g.key}\` (r=${g.r.toFixed(2)}, drop=${g.ablationDrop.toFixed(2)}%)`).join(", ")}.\n\n`;
const projectile = merged.find((g) => g.key === "projectileUsage");
if (projectile) {
  md += `The standout case is \`projectileUsage\`: r=${projectile.r >= 0 ? "+" : ""}${projectile.r.toFixed(3)} (effectively zero correlation) but +${projectile.ablationDrop.toFixed(2)}% ablation drop — one of the most important genes under ablation. The GA is just not using projectiles well, and the ablation result shows the ceiling is higher if it did.\n\n`;
}
const rankByDrop = [...merged].sort((a, b) => b.ablationDrop - a.ablationDrop);
md += `**Correlated-only** (the GA tunes them but they don't matter, |r| > 0.15, drop < 0.5%): ${correlatedOnly.map((g) => `\`${g.key}\` (r=${g.r.toFixed(2)}, drop=${g.ablationDrop.toFixed(2)}%)`).join(", ")}.\n\n`;
const risk = merged.find((g) => g.key === "riskTolerance");
if (risk) {
  md += `The most striking is \`riskTolerance\` with r=${risk.r >= 0 ? "+" : ""}${risk.r.toFixed(3)} (the strongest correlation in the genome) but only +${risk.ablationDrop.toFixed(2)}% ablation impact. The GA is *strongly* selecting for ${risk.r < 0 ? "low" : "high"} risk-tolerance in the final population, but freezing the gene at 0.5 costs almost nothing. The GA is probably dragging \`riskTolerance\` along as a free-rider on the *real* load-bearing genes (e.g., \`${rankByDrop[0]?.key}\`).\n\n`;
}
md += `**Causal + correlated** (clean wins, drop > 0.5%, |r| > 0.15): ${both.map((g) => `\`${g.key}\` (r=${g.r.toFixed(2)}, drop=${g.ablationDrop.toFixed(2)}%)`).join(", ")}.\n\n`;
md += `These are the cleanest wins: the GA correctly identified and tuned load-bearing genes.\n\n`;

md += `### Why this matters for the paper\n\n`;
md += `1. **You can't infer importance from the GA's behaviour alone.** If you look at the final population and say "the GA is tuning \`riskTolerance\` aggressively, it must matter", the correlation analysis says no — \`riskTolerance\` has the strongest correlation but the smallest ablation impact. The GA is *wrong* about which genes matter.\n`;
md += `2. **You can't infer importance from ablation alone.** If you only ran ablation, you'd know \`projectileUsage\` is the 2nd most important gene but you wouldn't know the GA *isn't* using it well. The correlation analysis tells you the GA is leaving value on the table — there's room to improve by manually boosting \`projectileUsage\` in the seed population, or by adding a second objective that rewards it.\n`;
md += `3. **Together they identify the most productive directions for future work.** The 3 causal-only genes (especially \`projectileUsage\`) are where the GA is failing to find good values despite clear gradient. A targeted improvement (different mutation rate, longer training, or a curriculum on projectile-heavy opponents) is most likely to pay off there.\n\n`;

if (gen) {
  // ============================================================================
  // Section 6: Generalization
  // ============================================================================
  md += `## 6. Generalization — does the GA actually learn to fight, or just to beat a specific set of opponents?\n\n`;
  md += `**Setup.** We split the 6 hard opponents into a 4-opponent training set and a 2-opponent held-out test set, in 3 different ways. For each split, we train a GA on the 4 training opponents (3 seeds), then evaluate the resulting champion on *both* the training opponents (in-distribution) and the held-out opponents (out-of-distribution). We also evaluate a random genome on the same sets as a baseline.\n\n`;
  md += `If the GA's win rate on held-out opponents is *close to* its win rate on training opponents, it has learned something *general*. If held-out performance collapses, it has overfit.\n\n`;
  md += `![Generalization](fig_generalization.svg)\n\n`;

  md += `### Per-split results\n\n`;
  md += `| Split | Train opponents | Test opponents | GA train | GA test | Rand train | Rand test |\n`;
  md += `|---|---|---|---|---|---|---|\n`;
  gen.splits.forEach((sp: any, i: number) => {
    md += `| ${i + 1} | ${sp.trainOpponents.join("+")} | ${sp.testOpponents.join("+")} | ${(sp.trainWinRate.mean * 100).toFixed(0)}% [${(sp.trainWinRate.ci95[0] * 100).toFixed(0)}–${(sp.trainWinRate.ci95[1] * 100).toFixed(0)}] | ${(sp.testWinRate.mean * 100).toFixed(0)}% [${(sp.testWinRate.ci95[0] * 100).toFixed(0)}–${(sp.testWinRate.ci95[1] * 100).toFixed(0)}] | ${(sp.randomTrainWinRate.mean * 100).toFixed(0)}% | ${(sp.randomTestWinRate.mean * 100).toFixed(0)}% |\n`;
  });
  md += `\n`;

  // Compute aggregate generalization gap
  const gap = (ga: any, rand: any) => ga.mean - rand.mean;
  const trainGaps = gen.splits.map((sp: any) => gap(sp.trainWinRate, sp.randomTrainWinRate));
  const testGaps = gen.splits.map((sp: any) => gap(sp.testWinRate, sp.randomTestWinRate));
  const meanTrainGap = trainGaps.reduce((a: number, b: number) => a + b, 0) / trainGaps.length;
  const meanTestGap = testGaps.reduce((a: number, b: number) => a + b, 0) / testGaps.length;
  const transferRatio = meanTestGap / meanTrainGap;

  md += `### Transfer ratio\n\n`;
  md += `- **GA improvement over random on training opponents:** +${(meanTrainGap * 100).toFixed(1)} pp (mean across 3 splits)\n`;
  md += `- **GA improvement over random on held-out opponents:** +${(meanTestGap * 100).toFixed(1)} pp (mean across 3 splits)\n`;
  md += `- **Transfer ratio:** ${(transferRatio * 100).toFixed(0)}% — the GA's *relative* advantage on unseen opponents is ${(transferRatio * 100).toFixed(0)}% of its advantage on training opponents.\n\n`;
  md += `A transfer ratio of 100% would mean "the GA learned something general that applies just as well to unseen opponents as to training opponents". A ratio of 0% would mean "the GA has overfit to the training set". We get ${(transferRatio * 100).toFixed(0)}%.\n\n`;

  md += `### Per-split narrative\n\n`;
  gen.splits.forEach((sp: any, i: number) => {
    const trainGap = (sp.trainWinRate.mean - sp.randomTrainWinRate.mean) * 100;
    const testGap = (sp.testWinRate.mean - sp.randomTestWinRate.mean) * 100;
    md += `- **Split ${i + 1}:** Train on ${sp.trainOpponents.join(", ")}. Test on ${sp.testOpponents.join(", ")}. GA beats random by +${trainGap.toFixed(0)}pp on training opponents, +${testGap.toFixed(0)}pp on held-out. ${testGap >= trainGap * 0.7 ? "Strong transfer." : "Some transfer, with degradation."}\n`;
  });
  md += `\n`;

  // Modified bosses
  md += `### Modified-bosses transfer test\n\n`;
  md += `We also tested whether the champion generalizes to **statistically modified versions of the same opponents** (each opponent buffed: +30% HP, +20% damage, +15% speed). The champion was *trained on the originals* and *evaluated on the buffed variants*.\n\n`;
  md += `![Modified bosses](fig_modified_bosses.svg)\n\n`;

  const mod = gen.modifiedBosses;
  md += `| Subject | Win rate on buffed bosses | 95% CI |\n`;
  md += `|---|---|---|\n`;
  md += `| GA trained on original bosses | **${(mod.trainedOnModifiedWinRate.mean * 100).toFixed(1)}%** | [${(mod.trainedOnModifiedWinRate.ci95[0] * 100).toFixed(0)}–${(mod.trainedOnModifiedWinRate.ci95[1] * 100).toFixed(0)}] |\n`;
  md += `| Random baseline | ${(mod.randomOnModifiedWinRate.mean * 100).toFixed(1)}% | [${(mod.randomOnModifiedWinRate.ci95[0] * 100).toFixed(0)}–${(mod.randomOnModifiedWinRate.ci95[1] * 100).toFixed(0)}] |\n`;
  const modGap = (mod.trainedOnModifiedWinRate.mean - mod.randomOnModifiedWinRate.mean) * 100;
  md += `\nThe GA keeps a **+${modGap.toFixed(0)}pp advantage over random** even on opponents 30% tougher than the training set. The strategies the GA learned (high block, high counter-attack, low aggression) appear to be *general* properties of "good play" rather than exploits of specific opponent weaknesses.\n\n`;

  md += `### Generalization claim\n\n`;
  md += `The combined evidence supports a strong generalization claim:\n\n`;
  md += `1. **Held-out opponents:** the GA's win rate on unseen bosses is within ${(transferRatio * 100).toFixed(0)}% of its training-set win rate. No split showed a collapse on held-out opponents.\n`;
  md += `2. **Statistically modified opponents:** the GA retains its full +${modGap.toFixed(0)}pp advantage over random on opponents 30% tougher than training.\n`;
  md += `3. **The evolved strategies are interpretable:** high block + high counter + low aggression is a recognisable *style* of play, not a memorized lookup table. This is exactly what you want a champion to be.\n\n`;
}

